import java.io.IOException;
import java.io.InputStreamReader;

/**
 * Service class for file management operations.
 */
public class FileService {

    /**
     * Searches for files in a specified directory matching a given pattern.
     * Uses the system's 'find' command via bash.
     *
     * @param searchDir   The directory path to search in.
     * @param filePattern The file pattern to match (e.g., "*.java").
     * @return A newline-separated string of file paths, or an error message if the search fails.
     */
    public String findFilesWithPattern(String searchDir, String filePattern) {
        // Construct the bash command string.
        // -type f: search for files only.
        // -name: match the file pattern.
        // head -n 10: limit the results to a maximum of 10.
        // Note: Parameters are wrapped in single quotes to handle spaces, 
        // though further sanitization would be required for production environments.
        String command = String.format("find '%s' -type f -name '%s' | head -n 10", searchDir, filePattern);

        ProcessBuilder processBuilder = new ProcessBuilder("bash", "-c", command);
        StringBuilder output = new StringBuilder();
        StringBuilder errorLog = new StringBuilder();

        try {
            Process process = processBuilder.start();

            // Capture standard output
            try (BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()))) {
                String line;
                while ((line = reader.readLine()) != null) {
                    output.append(line).append(System.lineSeparator());
                }
            }

            // Capture error output
            try (BufferedReader errorReader = new BufferedReader(new InputStreamReader(process.getErrorStream()))) {
                String line;
                while ((line = errorReader.readLine()) != null) {
                    errorLog.append(line).append(System.lineSeparator());
                }
            }

            int exitCode = process.waitFor();

            if (exitCode != 0) {
                String errorMsg = errorLog.toString().trim();
                return "Error: Search failed with exit code " + exitCode + (errorMsg.isEmpty() ? "" : ": " + errorMsg);
            }

            return output.toString().trim();

        } catch (IOException e) {
            return "Error: I/O exception occurred during file search: " + e.getMessage();
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            return "Error: Search process was interrupted: " + e.getMessage();
        }
    }
}

